parameters.query:
query GetDatabaseRecords($orgId: ID!, $databasePipesId: ID!) {
  # (Optional) sanity check: fetch org name
  organization(id: $orgId) {
    id
    name
  }

  # Table (database) metadata + which org it belongs to
  table(id: $databasePipesId) {
    id
    name
    organization { id name }
  }

  # The actual records from this database (paginated)
  table_records(table_id: $databasePipesId, first: 50) {
    edges {
      node {
        id
        title
        record_fields {
          name
          value
        }
      }
    }
    pageInfo {
      endCursor
      hasNextPage
    }
  }
}

