  card(id: $cardId) {
    id
    title
    fields {
      field {
        id
        label
        type
      }
      value          # human-readable value
      report_value   # normalized value (useful for numbers/selects)
      array_value
    }
  }
}

=mutation ($cardId: ID!, $toAdd: [UndefinedInput!]!) {
  updateFieldsValues(
    input: {
      nodeId: $cardId
      values: [
        {
          fieldId: "cards_de_treinamentos"
          value: $toAdd          # e.g. ["123456789"] or multiple IDs
          operation: ADD         # append without replacing existing connections
        }
      ]
    }
  ) {
    success
    userErrors { field message }
    updatedNode {
      ... on Card { id }
    }
  }
}

