={{
(() => {
  const fields = $json.data?.card?.fields || [];
  const f = fields.find(x => (x.field?.id || x.indexName || "") === "id_solicita_ao");
  const arr = Array.isArray(f?.array_value)
    ? f.array_value
    : f?.value != null
      ? [f.value]
      : [];
  return arr
    .map(v => (typeof v === "string" ? v.trim() : String(v)))
    .filter(Boolean)
    .join(", "); // return as a single string
})()
}}

={{
(() => {
  const root = $input.all()[0].json;

  const fields =
    root?.body?.data?.card?.fields ??
    root?.data?.card?.fields ??
    root?.card?.fields ??
    [];

  const f = fields.find(x => {
    const id = (x?.field?.id ?? "").toLowerCase();
    const label = (x?.field?.label ?? "").toLowerCase();
    return id.includes("saas") || label.includes("saas") || id.includes("vers") || label.includes("vers");
  });

  const raw = (f?.report_value ?? f?.value ?? "") ?? "";
  const match = String(raw).match(/\d+(?:\.\d+)+|\d+(?:\.\d+)?/);
  return match ? match[0] : null;
})()
}}

