      return v.map(x => normalizeLabel(x)).filter(Boolean).join(", ");
    }
    if (typeof v === "object") {
      const txt = v.label ?? v.name ?? v.value ?? "";
      return normalizeLabel(txt);
    }
    let s = String(v);

    // If it looks like JSON (e.g., '["Rede A"]' or '"Rede A"'), try to parse first
    try {
      const parsed = JSON.parse(s);
      if (Array.isArray(parsed)) return parsed.map(x => clean(String(x))).filter(Boolean).join(", ");
      if (typeof parsed === "string") s = parsed;
    } catch (_) {}

    s = clean(s);

    // Strip wrapping quotes if present: "Rede A" -> Rede A
    s = s.replace(/^"(.*)"$/,'$1');

    // Strip a single pair of wrapping brackets if the whole thing is bracketed: [Rede A] -> Rede A
    if (s.startsWith("[") && s.endsWith("]")) {
      s = s.slice(1, -1).trim();
    }

    return s;
  };

  // ---- IDs from array_value ----
  const extractIds = (input) => {
    const out = [];
    const push = (v) => {
      if (v == null) return;
      if (Array.isArray(v)) return v.forEach(push);
      if (typeof v === "object") {
        if (v.id != null) out.push(String(v.id));
        else if (typeof v.value === "string")
          clean(v.value).split(/[\s,;|]+/).filter(Boolean).forEach(t => out.push(t));
        return;
      }
      if (typeof v === "number") return out.push(String(v));
      if (typeof v === "string")
        return clean(v).split(/[\s,;|]+/).filter(Boolean).forEach(t => out.push(t));
    };
    push(input);
    return out;
  };

  const ids = extractIds(f.array_value);

  // ---- Labels: prefer f.value; fallback to labels inside array_value objects ----
  let labels = [];
  if (Array.isArray(f.value)) {
    labels = f.value.map(normalizeLabel).filter(Boolean);
  } else if (typeof f.value === "string") {
    const s = normalizeLabel(f.value);
    // If multiple labels were packed in one string, split by commas/pipes
    labels = s.split(/[,|]+/).map(x => x.trim()).filter(Boolean);
  } else if (Array.isArray(f.array_value)) {
    labels = f.array_value.map(v => normalizeLabel(v)).filter(Boolean);
  }

  // Zip by index
  const max = Math.max(ids.length, labels.length);
  const pairs = [];
  for (let i = 0; i < max; i++) {
    const id = ids[i] ?? null;
    const label = (labels[i] ?? null);
    if (id !== null || (label && label.length)) pairs.push({ id, label });
  }
  return pairs;
})()
}}

