parameters.jsCode:
// n8n Code node (JavaScript)

const FIELD_IDS = {
  relCards: 'regras_de_faturamento', // campo conectado de cards (clientes/redes)
  histRede: 'auto_historico_de_redes',
  histClientes: 'auto_historico_de_clientes',
};

const arr = (v) => (Array.isArray(v) ? v.filter(Boolean) : []);
const uniqStr = (xs) => Array.from(new Set(xs.map((x) => String(x))));

const originCardId = $('Consultar card').item.json.data.card.id;

const toAddRedeIds = uniqStr(arr($json.toAddRedeId));
const toRemRedeIds = uniqStr(arr($json.toRemoveRedeId));
const toAddClienteIds = uniqStr(arr($json.toAddClientes));
const toRemClienteIds = uniqStr(arr($json.toRemoveClientes));

const hasLinkOps =
  toAddRedeIds.length || toRemRedeIds.length || toAddClienteIds.length || toRemClienteIds.length;

const changedRede = toAddRedeIds.length > 0 || toRemRedeIds.length > 0;
const changedCli  = toAddClienteIds.length > 0 || toRemClienteIds.length > 0;

const histUltimaRede = arr($json.histUltimaRede);
const histUltimosClientes = arr($json.histUltimosClientes);

// ---- Monta partes (body) ----
const parts = [];

// 1) Atualiza históricos no card de origem (1 chamada)
const histValues = [];
if (changedRede) {
  histValues.push(
    `{ fieldId: "${FIELD_IDS.histRede}", value: $histUltimaRede, operation: REPLACE }`
  );
}
if (changedCli) {
  histValues.push(
    `{ fieldId: "${FIELD_IDS.histClientes}", value: $histUltimosClientes, operation: REPLACE }`
  );
}
if (histValues.length) {
  parts.push(`
    hist: updateFieldsValues(input: {
      nodeId: $originCardId
      values: [ ${histValues.join('\n')} ]
    }) { success userErrors { field message } }
  `);
}

// 2) ADD/REMOVE do card de origem nos cards-alvo (clientes/redes)
let i = 0;
const addOp = (prefix, targetCardId, op) => {
  const alias = `${prefix}_${i++}`;
  parts.push(`
    ${alias}: updateFieldsValues(input: {
      nodeId: "${targetCardId}"
      values: [
        { fieldId: "${FIELD_IDS.relCards}", value: $originCardIdValue, operation: ${op} }
      ]
    }) { success userErrors { field message } }
  `);
};

toAddRedeIds.forEach((id) => addOp('addRede', id, 'ADD'));
toRemRedeIds.forEach((id) => addOp('remRede', id, 'REMOVE'));
toAddClienteIds.forEach((id) => addOp('addCliente', id, 'ADD'));
toRemClienteIds.forEach((id) => addOp('remCliente', id, 'REMOVE'));

// ---- Variáveis ----
const hasWork = parts.length > 0;

const varDefs = [`$originCardId: ID!`];
const variables = { originCardId };

if (hasLinkOps) {
  varDefs.push(`$originCardIdValue: [UndefinedInput!]!`);
  variables.originCardIdValue = [String(originCardId)];
}

if (changedRede) {
  varDefs.push(`$histUltimaRede: [UndefinedInput!]`);
  const csvRede = histUltimaRede.join(','); // "id1,id2"
  variables.histUltimaRede = [csvRede];     // ["id1,id2"]
}

if (changedCli) {
  varDefs.push(`$histUltimosClientes: [UndefinedInput!]`);
  const csv = histUltimosClientes.join(','); // "id1,id2"
  variables.histUltimosClientes = [csv];     // ["id1,id2"]
}

const query = hasWork
  ? `mutation SyncCards(${varDefs.join(', ')}) { ${parts.join('\n')} }`
  : '';

return [{ json: { hasWork, query, variables } }];

// n8n Code node (JavaScript)
// Lança erro se qualquer operação em data.* retornar success === false

const out = [];

for (const item of items) {
  const data = item.json?.data ?? {};
  const failures = [];

  for (const [opName, opResult] of Object.entries(data)) {
    if (opResult && typeof opResult === 'object' && opResult.success === false) {
      failures.push({
        operation: opName,
        userErrors: opResult.userErrors ?? [],
      });
    }
  }

  out.push({
    json: {
      ...item.json,
      hasFailures: failures.length > 0,
      failures,
      failureCount: failures.length,
    },
  });
}

const anyFailure = out.some(i => i.json.hasFailures);

if (anyFailure) {
  const allFailures = out.flatMap(i => i.json.failures);
  throw new Error(
    `Pipefy retornou success:false em ${allFailures.length} operação(ões): ${JSON.stringify(allFailures)}`
  );
}

return out;

const sd = $getWorkflowStaticData('global');
sd.logs = [];
sd.startedAt = new Date().toISOString();
return $input.all();

