const isBlankToken=(value)=>{
  const s=String(value ?? '').trim().toLowerCase();
  return s==='' || s==='null' || s==='undefined' || s==='nan';
};
const normalizeBillingDay=(value)=>{
  if(value===undefined || value===null) return null;
  if(typeof value==='number' && Number.isFinite(value)){
    const normalized=Math.trunc(value);
    return (normalized>=1 && normalized<=31) ? normalized : null;
  }
  const s=String(value).trim();
  if(!s) return null;
  const matches=s.match(/[0-9]+/g);
  if(!matches) return null;
  for(let idx=matches.length-1; idx>=0; idx-=1){
    const normalized=Number(matches[idx]);
    if(Number.isInteger(normalized) && normalized>=1 && normalized<=31){
      return normalized;
    }
  }
  return null;
};

const counters={
  skippedDay:0,
  skippedExisting:0,
  invalidRuleId:0,
  emptyItemTemplates:0
};
const ineligibleByReason={};
const countIneligibleReason=(reason)=>{
  const key=String(reason || 'unknown_reason');
  ineligibleByReason[key]=Number(ineligibleByReason[key] || 0) + 1;
};

const fieldMap=(fields)=>{
  const m={};
  for(const f of (fields || [])){
    const fid=f&&f.field ? f.field.id : null;
    if(fid) m[fid]=f;
  }
  return m;
};
const pickScalar=(f)=>{
  if(!f) return null;
  const rv=f.report_value;
  return (rv!==undefined && rv!==null && String(rv).trim()!=='') ? rv : f.value;
};
const extractIds=(f)=>{
  if(!f) return [];
  const av=f.array_value;
  const ids=[];
  const push=(x)=>{
    if(x===undefined || x===null) return;
    if(typeof x==='object'){
      if(x.id!=null) ids.push(String(x.id));
      else if(x.value!=null) ids.push(String(x.value));
      else if(x.label!=null) ids.push(String(x.label));
      else ids.push(JSON.stringify(x));
    }else{
      ids.push(String(x));
    }
  };

  if(Array.isArray(av)){
    for(const x of av) push(x);
  }else{
    const v=pickScalar(f);
    if(Array.isArray(v)){
      for(const x of v) push(x);
    }else if(typeof v==='string'){
      const ms=v.match(/[0-9]+/g);
      if(ms) for(const x of ms) ids.push(String(x));
      else if(v.trim()!=='') ids.push(v.trim());
    }else if(v!=null){
      push(v);
    }
  }

  return Array.from(new Set(ids.filter((s)=>s && String(s).trim()!==''))).map(String);
};

const registerIneligible=(payload)=>{
  const reason=String(payload?.reason || 'unknown_reason');
  countIneligibleReason(reason);
  ineligibleRules.push({
    ...payload,
    reason,
    competenciaYMD:runContext.competenciaYMD,
    compStart:runContext.compStart,
    compEnd:runContext.compEnd
  });
};

for(const r of rules){
  const ridRaw=String(r?.id ?? '').trim();
  const ruleTitle=String(r?.title || '');

  if(isBlankToken(ridRaw)){
    counters.invalidRuleId += 1;
    runContext.metrics.rulesInvalid=Number(runContext.metrics.rulesInvalid || 0) + 1;
    runContext.errors.push({
      event:'rule_invalid_id',
      reason:'missing_rule_id',
      details:{ruleTitle}
    });
    log({
      level:'error',
      event:'rule_skip_invalid_id',
      reason:'missing_rule_id',
      ruleTitle
    });
    registerIneligible({
      ruleId:null,
      ruleTitle,
      diaGeracao:null,
      reason:'missing_rule_id',
      reasonDetail:{ruleIdRaw:ridRaw || null},
      prefetchDecision:'invalid_rule'
    });
    continue;
  }

  const rid=String(ridRaw);
  const fm=fieldMap(r.fields);
  const rawDiaGeracao=pickScalar(fm['dia_de_gera_o_da_fatura']);
  const normalizedDiaGeracao=normalizeBillingDay(rawDiaGeracao);
  const diaGeracao=(normalizedDiaGeracao!==null)
    ? String(normalizedDiaGeracao)
    : String(rawDiaGeracao ?? '').trim();
  if(normalizedDiaGeracao!==todayDay){
    counters.skippedDay += 1;
    runContext.metrics.rulesSkippedDay=Number(runContext.metrics.rulesSkippedDay || 0) + 1;
    log({
      level:'info',
      event:'rule_skip_day',
      ruleId:rid,
      diaGeracao,
      rawDiaGeracao:rawDiaGeracao ?? null,
      normalizedDiaGeracao,
      expectedDay:todayDay,
      reason:'billing_day_mismatch'
    });
    registerIneligible({
      ruleId:rid,
      ruleTitle,
      diaGeracao,
      reason:'billing_day_mismatch',
      reasonDetail:{expectedDay:todayDay,actualDay:normalizedDiaGeracao,rawDiaGeracao:rawDiaGeracao ?? null},
      prefetchDecision:'billing_day_mismatch'
    });
    continue;
  }

  if(existing[rid]){
    counters.skippedExisting += 1;
    runContext.metrics.rulesSkippedExisting=Number(runContext.metrics.rulesSkippedExisting || 0) + 1;
    log({level:'info',event:'rule_skip_existing_invoice',ruleId:rid,competenciaYMD:runContext.competenciaYMD,prefetchDecision:'already_has_invoice',reason:'prefetch_found_invoice'});
    registerIneligible({
      ruleId:rid,
      ruleTitle,
      diaGeracao,
      reason:'prefetch_found_invoice',
      reasonDetail:{competenciaYMD:runContext.competenciaYMD},
      existingInvoiceId:existing[rid] ?? null,
      prefetchDecision:'already_has_invoice'
    });
    continue;
  }

  const itemIds=extractIds(fm['itens_da_fatura']);
  if(itemIds.length===0){
    counters.emptyItemTemplates += 1;
    log({level:'warn',event:'rule_no_item_templates',ruleId:rid,reason:'empty_item_template_list'});
  }

  eligibleRules.push({
    ruleId:rid,
    ruleTitle,
    diaGeracao,
    itemTemplateIds:itemIds,
    ruleFields:fm,
    competenciaYMD:runContext.competenciaYMD,
    compStart:runContext.compStart,
    compEnd:runContext.compEnd,
    prefetchDecision:'new_rule_candidate'
  });
}

runContext.metrics.rulesEligible=eligibleRules.length;
runContext.metrics.rulesIneligible=ineligibleRules.length;
log({
  level:'info',
  event:'rules_classified',
  eligible:eligibleRules.length,
  ineligible:ineligibleRules.length,
  totalRules:rules.length,
  counters,
  ineligibleByReason
});

if(eligibleRules.length===0){
  runContext.logs.push({
    ts:new Date().toISOString(),
    level:'info',
    event:'prep_completed_no_eligible_rules',
    reason:'no_rule_eligible_after_filters',
    counters,
    ineligibleByReason
  });
}

return [{json:{
  kind:'prep_classification',
  eligibleRules,
  ineligibleRules,
  counters,
  ineligibleByReason
}}];

